1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	type Item = {
12	  type: string;
13	  material?: string;
14	  enchantment?: number;
15	  cursed?: boolean;
16	};
17	type QuoteStep = { op: "quote"; items: Item[] };
18	type Damage = { itemType: string; amount: number };
19	type ClaimStep = {
20	  op: "claim";
21	  policy: number;
22	  incident: { cause: string; damages: Damage[] };
23	};
24	type Step = QuoteStep | ClaimStep;
25	type Customer = { yearsWithMHPCO: number };
26	type Scenario = { customer: Customer; steps: Step[] };
27	
28	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
29	
30	const INSURANCE_VALUE: Record<string, number> = {
31	  sword: 1000,
32	  amulet: 600,
33	  staff: 800,
34	  potion: 400,
35	  rune: 250,
36	  moonstone: 250,
37	};
38	
39	const insuranceValueFor = (type: string): number => INSURANCE_VALUE[type] ?? 0;
40	
41	const DEDUCTIBLE = 100;
42	const CAP_MULTIPLIER = 2;
43	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
44	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
45	
46	const FIRST_INSURANCE_RATE = 0.1;
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	const BLOCK_SIZE = 3;
50	const BLOCK_BASE_PREMIUM = 60;
51	
52	const countByType = (items: Item[]): Map<string, number> => {
53	  const counts = new Map<string, number>();
54	  for (const item of items) {
55	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
56	  }
57	  return counts;
58	};
59	
60	const groupBase = (type: string, count: number): number =>
61	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
62	    ? BLOCK_BASE_PREMIUM
63	    : count * basePremiumFor(type);
64	
65	const policyBase = (items: Item[]): number =>
66	  Array.from(countByType(items)).reduce(
67	    (total, [type, count]) => total + groupBase(type, count),
68	    0,
69	  );
70	
71	const LOYALTY_RATE = 0.2;
72	const LOYALTY_THRESHOLD_YEARS = 2;
73	const FOLLOW_UP_RATE = 0.15;
74	
75	type PolicyContext = { customer: Customer; isFollowUp: boolean };
76	
77	type PolicyModifier = {
78	  applies: (ctx: PolicyContext) => boolean;
79	  rate: number;
80	  sign: 1 | -1;
81	};
82	
83	const POLICY_MODIFIERS: PolicyModifier[] = [
84	  { applies: () => true, rate: FIRST_INSURANCE_RATE, sign: +1 },
85	  {
86	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
87	    rate: LOYALTY_RATE,
88	    sign: -1,
89	  },
90	  { applies: (ctx) => ctx.isFollowUp, rate: FOLLOW_UP_RATE, sign: -1 },
91	];
92	
93	const policyAdjustments = (base: number, ctx: PolicyContext): number =>
94	  POLICY_MODIFIERS.reduce(
95	    (total, mod) => total + (mod.applies(ctx) ? mod.sign * base * mod.rate : 0),
96	    0,
97	  );
98	
99	const CURSE_RATE = 0.5;
100	const HIGH_ENCHANTMENT_RATE = 0.3;
101	const HIGH_ENCHANTMENT_THRESHOLD = 5;
102	
103	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
104	  applies ? basePremiumFor(item.type) * rate : 0;
105	
106	const curseSurcharge = (item: Item): number =>
107	  surchargeWhen(item, item.cursed === true, CURSE_RATE);
108	
109	const highEnchantmentSurcharge = (item: Item): number =>
110	  surchargeWhen(
111	    item,
112	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
113	    HIGH_ENCHANTMENT_RATE,
114	  );
115	
116	const itemSurcharges = (items: Item[]): number =>
117	  items.reduce(
118	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
119	    0,
120	  );
121	
122	const quotePremium = (items: Item[], ctx: PolicyContext): number => {
123	  const base = policyBase(items);
124	  return Math.ceil(
125	    base + itemSurcharges(items) + policyAdjustments(base, ctx) + PROCESSING_FEE,
126	  );
127	};
128	
129	const insuranceSum = (items: Item[]): number =>
130	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
131	
132	const capFor = (items: Item[]): number => CAP_MULTIPLIER * insuranceSum(items);
133	
134	const reimbursableAmount = (amount: number, item: Item | undefined): number => {
135	  const isHighEnchantment =
136	    (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
137	  return isHighEnchantment ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE : amount;
138	};
139	
140	const damagePayout = (damage: Damage, item: Item | undefined): number =>
141	  reimbursableAmount(damage.amount, item) - DEDUCTIBLE;
142	
143	const claimPayout = (claim: ClaimStep, items: Item[]): number =>
144	  claim.incident.damages.reduce(
145	    (sum, d) => sum + damagePayout(d, items.find((i) => i.type === d.itemType)),
146	    0,
147	  );
148	
149	type QuoteResult = { premium: number };
150	type ClaimResult = { payout: number; remainingCap: number };
151	type StepResult = QuoteResult | ClaimResult;
152	type ScenarioResult = { results: StepResult[] };
153	
154	type PolicyLedger = {
155	  registerQuote: (index: number, items: Item[]) => void;
156	  isFollowUp: () => boolean;
157	  itemsFor: (policy: number) => Item[];
158	  recordClaim: (policy: number, payout: number) => number;
159	};
160	
161	const createPolicyLedger = (): PolicyLedger => {
162	  const remainingCaps = new Map<number, number>();
163	  const policyItems = new Map<number, Item[]>();
164	  return {
165	    registerQuote: (index, items) => {
166	      remainingCaps.set(index, capFor(items));
167	      policyItems.set(index, items);
168	    },
169	    isFollowUp: () => remainingCaps.size > 0,
170	    itemsFor: (policy) => policyItems.get(policy) ?? [],
171	    recordClaim: (policy, payout) => {
172	      const remaining = (remainingCaps.get(policy) ?? 0) - payout;
173	      remainingCaps.set(policy, remaining);
174	      return remaining;
175	    },
176	  };
177	};
178	
179	const handleQuote = (
180	  step: QuoteStep,
181	  index: number,
182	  customer: Customer,
183	  ledger: PolicyLedger,
184	): QuoteResult => {
185	  const ctx: PolicyContext = { customer, isFollowUp: ledger.isFollowUp() };
186	  ledger.registerQuote(index, step.items);
187	  return { premium: quotePremium(step.items, ctx) };
188	};
189	
190	const handleClaim = (step: ClaimStep, ledger: PolicyLedger): ClaimResult => {
191	  const payout = Math.floor(claimPayout(step, ledger.itemsFor(step.policy)));
192	  const remainingCap = ledger.recordClaim(step.policy, payout);
193	  return { payout, remainingCap };
194	};
195	
196	export const processScenario = (scenario: Scenario): ScenarioResult => {
197	  const ledger = createPolicyLedger();
198	  const results = scenario.steps.map((step, index) =>
199	    step.op === "quote"
200	      ? handleQuote(step, index, scenario.customer, ledger)
201	      : handleClaim(step, ledger),
202	  );
203	  return { results };
204	};
